#include<bits/stdc++.h>
using namespace std;
long long mod;
long long niyuan(int a,int b){//2维 
	long long res=1;
	while(b){
		if(b&1){
			res=res*a%mod;
		}
		a=a*a%mod;
		b>>=1;
	}
	return res;
}
long long inv[30000001];
void ny(int n,int p){
	inv[1]=1;
	for(int i=2;i<=n;i++)inv[i]=p-(p/i*inv[p%i]%p)%p;
	for(int i=1;i<=n;i++)cout<<inv [i]<<"\n";
}
int main()
{
	ios::sync_with_stdio(false);
	cin.tie(0);
	cout.tie(0);
	long long a;
	cin>>a>>mod;
	ny(a,mod);
}
